#include <stdio.h>
#include <string.h>

char todoList[10][50];
int taskCount = 0;

void showMenu() {
    printf("\n=== YAPILACAKLAR LISTESI ===\n");
    printf("1. Gorev Ekle\n");
    printf("2. Gorevleri Listele\n");
    printf("3. Gorev Sil\n");
    printf("4. Cikis\n");
}

void addTask(char* task) {
    strcpy(todoList[taskCount], task);
    taskCount++;
    printf("Eklendi: '%s'\n", task);
}

void listTasks() {
    if (taskCount == 0) {
        printf("Liste bos.\n");
        return;
    }

    for (int i = 0; i < taskCount; i++) {
        printf("%d. %s\n", i + 1, todoList[i]);
    }
}

void removeTask(int index) {
    if (index >= 0 && index < taskCount) {
        printf("Silindi: '%s'\n", todoList[index]);
        for (int i = index; i < taskCount - 1; i++) {
            strcpy(todoList[i], todoList[i + 1]);
        }
        taskCount--;
    } else {
        printf("Gecersiz numara.\n");
    }
}

int main() {
    showMenu();

    printf("\n> Secim: 1\n");
    addTask("Markete git");

    printf("\n> Secim: 1\n");
    addTask("Kod yaz");

    printf("\n> Secim: 1\n");
