    printf("\n> Secim: 2\n");
    listTasks();

    printf("\n> Secim: 3 (1. gorevi sil)\n");
    removeTask(0);

    printf("\n> Secim: 2\n");
    listTasks();

    printf("\n> Secim: 4\n");
    printf("Programdan cikiliyor...\n");

    return 0;
}
